#include<bits/stdc++.h>
using namespace std;
struct COW{
	int pos,h;
}cow[1001];
bool cmp(COW a,COW b){
	return a.pos<b.pos;
}
int n;
bool flag[1001];
int main()
{
	cin>>n;
	for(int i=0;i<n;i++){
		cin>>cow[i].pos>>cow[i].h;
	}
	sort(&cow[0],&cow[n],cmp);
	int R=1000001;
	for(int i=0;i<n-1;i++){
		if(cow[i].h!=cow[i+1].h){
			R=min(R,cow[i+1].pos-cow[i].pos);
		}
	}
	R--;
	int cnt=0;
	for(int i=0;i<n;i++){
		if(!cow[i].h||flag[i]){
			continue;
		}
		
		flag[i]=true;cnt++;
	//	cout<<i<<' '<<cnt<<endl;
		for(int j=i+1;j<n;j++){
			if(cow[j].pos-cow[j-1].pos<=R){
				flag[j]=true;
			}
			else{				
				break;
			}
		}
	}
	cout<<cnt;
}
